import numpy as np
from app.strategy.base import BaseStrategy


class AdaptiveMomentumVIX(BaseStrategy):
    name = 'Adaptive Momentum VIX Regime'
    multi_asset = True

    def __init__(self, params=None):
        cfg = {
            'mom_long': 252,
            'mom_skip': 21,
            'sma_window': 200,
            'n_hold': 3,
            'rebal': 21,
            'alloc': 0.95,
            'vol_window': 63,
            'target_vol': 0.18,
            'max_scale': 1.5,
            'vix_low': 18,
            'vix_high': 28,
        }
        if params:
            cfg.update(params)
        super().__init__(cfg)

    def _mom(self, series, bar):
        p = self.params
        if bar < p['mom_long']:
            return None
        try:
            p0 = float(series.iloc[bar - p['mom_skip']])
            pw = float(series.iloc[bar - p['mom_long']])
            if pw <= 0 or p0 <= 0:
                return None
            return p0 / pw - 1.0
        except Exception:
            return None

    def _above_sma(self, series, bar):
        p = self.params
        w = p['sma_window']
        if bar < w:
            return False
        try:
            curr = float(series.iloc[bar])
            sma = float(series.iloc[bar - w:bar].mean())
            return curr > sma
        except Exception:
            return False

    def _rvol(self, series, bar):
        p = self.params
        lb = p['vol_window']
        if bar < lb + 1:
            return 0.15
        rets = series.iloc[bar - lb:bar].pct_change().dropna()
        if len(rets) < 5:
            return 0.15
        return max(float(rets.std() * np.sqrt(252)), 0.01)

    def generate_signals(self, data: dict) -> dict:
        syms = list(data.keys())
        idx = data[syms[0]].index
        nb = len(idx)
        p = self.params

        out = {s: pd.DataFrame({'signal': 0, 'size_pct': 0.0}, index=idx) for s in syms}
        hold = {}
        warm = p['mom_long'] + 5

        offensive = [s for s in ['SPY', 'QQQ', 'IWM', 'VTI', 'EFA'] if s in data]
        defensive = [s for s in ['TLT', 'GLD', 'AGG'] if s in data]

        for bar in range(warm, nb):
            dt = idx[bar]

            if bar % p['rebal'] != 0:
                for s, w in hold.items():
                    if s in out:
                        out[s].at[dt, 'signal'] = 1
                        out[s].at[dt, 'size_pct'] = w
                continue

            # Macro regime via VIX and yield curve
            vix = self.macro.get('VIXCLS', dt) if hasattr(self, 'macro') else None
            t10y2y = self.macro.get('T10Y2Y', dt) if hasattr(self, 'macro') else None

            regime = 'risk_on'
            if vix is not None and vix >= p['vix_high']:
                regime = 'risk_off'
            elif (vix is not None and vix >= p['vix_low']) or (t10y2y is not None and t10y2y < -0.5):
                regime = 'mixed'

            # 12-1 momentum with 200d SMA filter for offensive
            off_scores = {}
            for s in offensive:
                m = self._mom(data[s]['close'], bar)
                trend = self._above_sma(data[s]['close'], bar)
                if m is not None and trend and m > 0:
                    off_scores[s] = m

            def_scores = {}
            for s in defensive:
                m = self._mom(data[s]['close'], bar)
                if m is not None:
                    def_scores[s] = m

            new_hold = {}

            if regime == 'risk_off':
                # Full defensive: best by momentum
                if def_scores:
                    best_def = max(def_scores, key=def_scores.get)
                    new_hold = {best_def: p['alloc']}

            elif regime == 'mixed':
                # Top 1 equity + best defensive, inverse-vol weighted
                top_off = sorted(off_scores.items(), key=lambda x: x[1], reverse=True)[:1]
                if top_off and def_scores:
                    eq_s = top_off[0][0]
                    def_s = max(def_scores, key=def_scores.get)
                    eq_vol = self._rvol(data[eq_s]['close'], bar)
                    def_vol = self._rvol(data[def_s]['close'], bar)
                    total_inv = 1.0 / eq_vol + 1.0 / def_vol
                    new_hold = {
                        eq_s: (1.0 / eq_vol / total_inv) * p['alloc'],
                        def_s: (1.0 / def_vol / total_inv) * p['alloc'],
                    }
                elif top_off:
                    new_hold = {top_off[0][0]: p['alloc'] * 0.6}
                elif def_scores:
                    new_hold = {max(def_scores, key=def_scores.get): p['alloc']}

            else:  # risk_on
                if off_scores:
                    top = sorted(off_scores.items(), key=lambda x: x[1], reverse=True)[:p['n_hold']]
                    vols = {s: self._rvol(data[s]['close'], bar) for s, _ in top}
                    inv_vols = {s: 1.0 / v for s, v in vols.items()}
                    total_inv = sum(inv_vols.values())
                    rp_weights = {s: iv / total_inv for s, iv in inv_vols.items()}

                    port_vol = sum(rp_weights[s] * vols[s] for s in rp_weights)
                    scale = min(p['target_vol'] / port_vol, p['max_scale']) if port_vol > 0 else 1.0

                    for s, w in rp_weights.items():
                        new_hold[s] = w * scale * p['alloc']

                    total = sum(new_hold.values())
                    if total > p['alloc']:
                        new_hold = {s: w * p['alloc'] / total for s, w in new_hold.items()}
                else:
                    # No qualified offensive: fallback to best defensive
                    if def_scores:
                        best_def = max(def_scores, key=def_scores.get)
                        new_hold = {best_def: p['alloc']}

            for s in syms:
                out[s].at[dt, 'signal'] = 0
                out[s].at[dt, 'size_pct'] = 0.0
            for s, w in new_hold.items():
                if s in out:
                    out[s].at[dt, 'signal'] = 1
                    out[s].at[dt, 'size_pct'] = float(w)

            hold = new_hold

        return out
